SELECT count(*) FROM keyword, movie_keyword, title, cast_info, char_name, name, role_type, aka_name WHERE movie_keyword.keyword_id = keyword.id AND movie_keyword.movie_id = title.id AND cast_info.movie_id = title.id AND cast_info.person_role_id = char_name.id AND cast_info.person_id = name.id AND cast_info.role_id = role_type.id AND aka_name.person_id = name.id;